import{_ as a,c as t,o as r,ae as o}from"./chunks/framework.Cqi9LMMK.js";const _=JSON.parse('{"title":"Расширение браузера","description":"","frontmatter":{"title":"Расширение браузера"},"headers":[],"relativePath":"install/extension.md","filePath":"install/extension.md"}'),n={name:"install/extension.md"};function i(l,e,s,h,p,c){return r(),t("div",null,[...e[0]||(e[0]=[o('<p>Vue Inspector доступен в нескольких вариантах запуска, чтобы инструмент можно было использовать в разных рабочих средах и браузерах.</p><p>Выбор варианта зависит от ограничений среды, требований безопасности и предпочтительного способа работы.</p><hr><h2 id="доступные-варианты-запуска" tabindex="-1">Доступные варианты запуска <a class="header-anchor" href="#доступные-варианты-запуска" aria-label="Permalink to &quot;Доступные варианты запуска&quot;">​</a></h2><h3 id="автономное-приложение" tabindex="-1">Автономное приложение <a class="header-anchor" href="#автономное-приложение" aria-label="Permalink to &quot;Автономное приложение&quot;">​</a></h3><p>Отдельная версия инструмента, не зависящая от установки браузерного расширения.</p><p>Подходит для сред, где использование расширений ограничено корпоративной политикой, а также для работы в браузерах, где требуется независимый запуск приложения.</p><p>Автономная версия может использоваться как универсальный способ запуска независимо от браузера.</p><hr><h3 id="расширение-для-chrome" tabindex="-1">Расширение для Chrome <a class="header-anchor" href="#расширение-для-chrome" aria-label="Permalink to &quot;Расширение для Chrome&quot;">​</a></h3><p>Версия инструмента в формате браузерного расширения.</p><p>Позволяет запускать Vue Inspector непосредственно на странице, использовать автоматический запуск, оконный режим, popup-меню и режим Devtools.</p><hr><h2 id="что-выбрать" tabindex="-1">Что выбрать? <a class="header-anchor" href="#что-выбрать" aria-label="Permalink to &quot;Что выбрать?&quot;">​</a></h2><ul><li><strong>Автономное приложение</strong> — если установка расширений недоступна или требуется независимый запуск;</li><li><strong>Расширение для Chrome</strong> — если нужен постоянный доступ к инструменту внутри браузера;</li></ul>',15)])])}const m=a(n,[["render",i]]);export{_ as __pageData,m as default};
